// 1. جلب البيانات القادمة من الـ AI Agent
const inputData = $input.item.json;

// التحقق الرئيسي لمنع توقف السير والتأكد من وجود حقل output
if (inputData && inputData.output) {
    const data = inputData.output;

    // 2. [صمام الأمان]: استخراج وتصفية القيمة القادمة من الـ Agent بعد تعريف data
    let rawTarget = (data.email_target || "").toLowerCase();
    let finalTarget = "none";
// جلب قيم الحذف من الـ Agent
    // جلب قيم الحذف من الـ Agent
    // 1. التأكد من تحويل الـ ID الخاص بالإضافة إلى رقم صحيح صافي
    if (data.Metadata_Context && data.Metadata_Context.ID) {
        let parsedId = parseInt(data.Metadata_Context.ID.toString().replace(/\D/g, ''), 10);
        data.Metadata_Context.ID = isNaN(parsedId) ? Math.floor(100000 + Math.random() * 900000) : parsedId;
    }

    // 2. صمام أمان لمعالجة طلبات الحذف واستنتاج الهدف
    let rawAction = (data.action_type || "create").toLowerCase();
    let deleteTarget = (data.delete_search_term || data.target_decision_id || "none").toString().trim();

    if (rawAction === "delete") {
        if (deleteTarget.toUpperCase().includes("LAST") || deleteTarget.includes("آخر") || deleteTarget.includes("اخر")) {
            deleteTarget = "LAST";
        }
    }
    if (rawTarget.includes("metadata") || rawTarget.includes("context") || rawTarget.includes("قرار")) {
        finalTarget = "metadata";
    } else if (rawTarget.includes("scoring") || rawTarget.includes("درج") || rawTarget.includes("تقييم")) {
        finalTarget = "scoring";
    } else if (rawTarget.includes("analysis") || rawTarget.includes("تحليل") || rawTarget.includes("تشخيص")) {
        finalTarget = "analysis";
    } else if (rawTarget.includes("recommend") || rawTarget.includes("توصي") || rawTarget.includes("خطة")) {
        finalTarget = "recommendation";
    } else if (rawTarget.includes("all") || rawTarget.includes("كل") || rawTarget.includes("الكامل")) {
        finalTarget = "all";
    } else if (rawTarget !== "none" && rawTarget.includes("@")) {
        // إذا كتب الـ Agent بريداً إلكترونياً بالخطأ، نعتبر تلقائياً أنه يريد إرسال التقرير كاملاً
        finalTarget = "all";
    }

    // 3. بناء رسالة نصية منسقة ومنظمة لعرضها في الشات بناءً على البيانات المستخرجة
    const formattedMessage = `
## 🧠 قرار: ${data.Metadata_Context?.Decision || 'غير محدد'}
---
📊 **البيانات التعريفية والتقييم:**
* **نوع القرار:** ${data.Metadata_Context?.Decision_Classification || '-'}
* **معرّف القرار (ID):** ${data.Metadata_Context?.ID || '-'}
* **التقييم الكمي الإجمالي:** ${data.Quantitative_Scoring?.Total_Score || '0'} من 14

📋 **خطة العمل التنفيذية (Action Plan):**
${data.Execution_Recommendation?.Action_Plan || '-'}

⚠️ **إدارة المخاطر والحلول البديلة:**
${data.Execution_Recommendation?.Risk_Mitigations || '-'}

💡 **التوصية النهائية:**
${data.Execution_Recommendation?.Recommendation || '-'}
`.trim();

    // 4. إرجاع البيانات مجهزة ومقسمة للأقسام الأصلية للجداول والإيميل
    return [{
        json: {
            Metadata_Context: data.Metadata_Context,
            Quantitative_Scoring: data.Quantitative_Scoring,
            Qualitative_Analysis_Diagnosis: data.Qualitative_Analysis,
            Execution_Recommendation: data.Execution_Recommendation,
            message: formattedMessage,
            is_status_message: false,
            send_email_target: finalTarget,
            action_type: rawAction,
            delete_target: deleteTarget// هذا الحقل سيحتوي على الكلمة المستنتجة (مثل: السفر، الشغل، أو LAST)تمرير القيمة المصفاة بنجاح
        }
    }];

} else {
    // في حال أرسل البوت نصاً عادياً أو ترحيبياً دون جداول بيانات
    return [{
        json: {
            message: inputData.output || ",لم يتم استخراج بيانات محددة.",
            is_status_message: true
        }
    }];
}

